import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Sanitizing user input using ESAPI encoder
        String sanitizedInput = null;
        try {
            sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Error sanitizing user input");
            e.printStackTrace();
            return;
        }

        // Properly handling sanitized user input
        String output = "<div>" + sanitizedInput + "</div>";

        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
